mapper.update:
update student
name = #{name}, gender = #{gender}, class_id = #{classId}, status = #{status}, id_card = #{idCard}, phone = #{phone}, account_status = #{accountStatus},
where id = #{id}

mapper.select:
select s.id, s.student_no, s.name, s.gender, c.class_name, s.status, s.account_status, s.create_time
from student s
left join class c on s.class_id = c.id

    s.name like CONCAT('%', #{name}, '%')
    s.student_no like CONCAT('%', #{studentNo}, '%')
    s.class_id = #{classId}
    s.status = #{status}
    s.account_status = #{accountStatus}

order by s.create_time desc
